import { useState, useEffect } from 'react';

function Dashboard({ userId }) {
  const [state, setState] = useState({ user: null, posts: null, loading: true, errors: {} });

  useEffect(() => {
    let cancelled = false;

    async function load() {
      // Use allSettled so one failing endpoint doesn't block the whole page:
      const results = await Promise.allSettled([
        fetch(`/api/users/${userId}`).then(r => r.json()),
        fetch(`/api/posts?userId=${userId}`).then(r => r.json()),
      ]);

      if (cancelled) return;

      const [userResult, postsResult] = results;

      setState({
        user:    userResult.status === 'fulfilled'  ? userResult.value  : null,
        posts:   postsResult.status === 'fulfilled' ? postsResult.value : null,
        loading: false,
        errors: {
          user:  userResult.status  === 'rejected' ? userResult.reason.message  : null,
          posts: postsResult.status === 'rejected' ? postsResult.reason.message : null,
        },
      });
    }

    load();
    return () => { cancelled = true; };
  }, [userId]);

  if (state.loading) return <p>Loading dashboard...</p>;

  return (
    <div>
      {state.errors.user  && <p className="error">User data unavailable: {state.errors.user}</p>}
      {state.errors.posts && <p className="error">Posts unavailable: {state.errors.posts}</p>}
      {state.user  && <UserCard user={state.user} />}
      {state.posts && <PostList posts={state.posts} />}
    </div>
  );
}

// Reusable hook with built-in timeout:
function useFetchWithTimeout(url, timeoutMs = 8000) {
  const [data, setData]     = useState(null);
  const [error, setError]   = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const controller = new AbortController();
    let timeoutId;

    async function load() {
      try {
        const timeoutPromise = new Promise((_, reject) => {
          timeoutId = setTimeout(
            () => reject(new Error(`Timed out after ${timeoutMs}ms`)),
            timeoutMs
          );
        });

        const fetchPromise = fetch(url, { signal: controller.signal })
          .then(r => {
            if (!r.ok) throw new Error(`HTTP ${r.status}`);
            return r.json();
          });

        const result = await Promise.race([fetchPromise, timeoutPromise]);
        setData(result);
      } catch (err) {
        if (err.name !== 'AbortError') setError(err.message);
      } finally {
        setLoading(false);
        clearTimeout(timeoutId);
      }
    }

    load();
    return () => {
      controller.abort();
      clearTimeout(timeoutId);
    };
  }, [url, timeoutMs]);

  return { data, error, loading };
}

// Scenario: load 3 independent modules; if any takes over 3s, use cached version instead.
