async function loadWithFallback(module) {
  const freshPromise  = fetch(`/api/${module}`).then(r => r.json());
  const cachedPromise = getCache(module);                   // resolves from localStorage
  const timeoutPromise = new Promise(resolve =>
    setTimeout(() => resolve(null), 3000)                   // null = 'timed out'
  );

  // Prefer fresh, fall back to cache, give up after 3s:
  return Promise.race([freshPromise, timeoutPromise])
    .then(result => result ?? cachedPromise);               // if null (timeout), use cache
}

