import { describe, it, expect } from 'vitest';

describe('Promise.all', () => {
  it('resolves with all values in order', async () => {
    const result = await Promise.all([
      Promise.resolve(1),
      Promise.resolve(2),
      Promise.resolve(3),
    ]);
    expect(result).toEqual([1, 2, 3]);
  });

  it('rejects when any input rejects', async () => {
    await expect(
      Promise.all([Promise.resolve(1), Promise.reject(new Error('boom')), Promise.resolve(3)])
    ).rejects.toThrow('boom');
  });
});

describe('Promise.allSettled', () => {
  it('never rejects and includes all outcomes', async () => {
    const results = await Promise.allSettled([
      Promise.resolve('ok'),
      Promise.reject(new Error('fail')),
    ]);
    expect(results[0]).toEqual({ status: 'fulfilled', value: 'ok' });
    expect(results[1].status).toBe('rejected');
    expect(results[1].reason.message).toBe('fail');
  });
});

describe('Promise.race', () => {
  it('resolves with the first settled value', async () => {
    const fast = Promise.resolve('fast');
    const slow = new Promise(resolve => setTimeout(() => resolve('slow'), 100));
    const result = await Promise.race([fast, slow]);
    expect(result).toBe('fast');
  });
});

describe('Promise.any', () => {
  it('ignores rejections if any promise fulfills', async () => {
    const result = await Promise.any([
      Promise.reject(new Error('fail')),
      Promise.resolve('success'),
    ]);
    expect(result).toBe('success');
  });

  it('rejects with AggregateError when all reject', async () => {
    await expect(
      Promise.any([Promise.reject(new Error('a')), Promise.reject(new Error('b'))])
    ).rejects.toThrow(AggregateError);
  });
});

