async function fetchFromFastest(urls) {
  const controllers = urls.map(() => new AbortController());

  const fetches = urls.map((url, i) =>
    fetch(url, { signal: controllers[i].signal })
      .then(r => r.json())
  );

  try {
    const result = await Promise.any(fetches);
    // Cancel all remaining in-flight requests:
    controllers.forEach(c => c.abort());
    return result;
  } catch (err) {
    throw err;
  }
}

// Decision flowchart in code:
function chooseCorrectCombinator(scenario) {
  if (scenario.needAllResults && scenario.failFast)     return Promise.all;
  if (scenario.needAllResults && !scenario.failFast)    return Promise.allSettled;
  if (scenario.firstToSettle)                          return Promise.race;
  if (scenario.firstToSucceed)                         return Promise.any;
}
